#include <iostream>
#include <iomanip>
#include <string>

class BankAccount {
public:
    double balance;

    void deposit(double amount) {
        balance += amount;
    }

    void withdraw(double amount) {
        balance -= amount;
    }
};

int main() {
    double initial;
    std::cin >> initial;
    BankAccount acct;
    acct.balance = initial;

    int n;
    std::cin >> n;
    std::cout << std::fixed << std::setprecision(2);
    for (int i = 0; i < n; ++i) {
        char op;
        double amount;
        std::cin >> op >> amount;
        if (op == 'D') {
            acct.deposit(amount);
        } else {
            acct.withdraw(amount);
        }
        std::cout << acct.balance << "\n";
    }
    std::cout << "Final: " << acct.balance << "\n";
    return 0;
}

